Now that we have a basic structure, we should write some unit tests to ensure it behaves as expected. Create a file named `test_scheduler.py`.

```json
{"name": "write_file", "arguments": {"path": "test_scheduler.py", "content": "# test_scheduler.py
import unittest
from scheduler import Scheduler, Job, CycleError, ValueError
class TestScheduler(unittest.TestCase):
    def setUp(self):
        self.scheduler = Scheduler()

    def test_add_job(self):
        job = Job('test_job', func=lambda: 'result')
        self.scheduler.add_job('test_job', func=job.func)
        self.assertIn('test_job', self.scheduler.jobs)

    def test_run_job_success(self):
        job = Job('test_job', func=lambda: 'result')
        self.scheduler.add_job('test_job', func=job.func)
        self.scheduler.run()
        result = self.scheduler.get_result('test_job')
        self.assertEqual(result, 'result')

    def test_run_cycle(self):
        job1 = Job('job1', dependencies=['job2'], func=lambda: 'result')
        job2 = Job('job2', dependencies=['job1'], func=lambda: 'result')
        self.scheduler.add_job('job1', dependencies=job1.dependencies)
        self.scheduler.add_job('job2', dependencies=job2.dependencies)
        self.assertRaises(CycleError, self.scheduler.run)

    def test_run_unknown_dependency(self):
        job = Job('test_job', dependencies=['unknown_job'], func=lambda: 'result')
        self.assertRaises(ValueError, self.scheduler.add_job, 'test_job', dependencies=job.dependencies)

if __name__ == '__main__':
    unittest.main()"}}
